<?php
namespace App\Modules\Hr\Compensation\Livewire;use App\Modules\Hr\Compensation\Actions\ManageBenefitAction;use App\Modules\Hr\Compensation\Actions\ManageSalaryBandAction;use App\Modules\Hr\Compensation\Actions\ManageSalaryRecordAction;use App\Modules\Hr\Compensation\Models\HrBenefit;use App\Modules\Hr\Compensation\Models\HrEmployeeBenefit;use App\Modules\Hr\Compensation\Models\HrSalaryBand;use App\Modules\Hr\Compensation\Models\HrSalaryRecord;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Personnel\Models\HrEmployee;use Livewire\Component;use Livewire\WithPagination;
class CompensationWorkspace extends Component{use WithPagination;public string $bandCode='';public string $bandName='';public string $bandMinimum='';public string $bandMidpoint='';public string $bandMaximum='';public string $bandEffectiveFrom='';public ?int $salaryEmployeeId=null;public ?int $salaryBandId=null;public string $grossSalary='';public string $salaryEffectiveFrom='';public string $salaryReason='';public string $benefitCode='';public string $benefitName='';public string $benefitType='meal';public string $employerCost='';public ?int $benefitEmployeeId=null;public ?int $benefitId=null;public string $benefitStartsOn='';public string $employeeContribution='';public string $statusFilter='';public string $sortField='created_at';public string $sortDirection='desc';public array $visibleColumns=['employee','version','gross','band','effective','status','actions'];public const COLUMNS=['employee'=>'Çalışan','version'=>'Sürüm','gross'=>'Brüt Ücret','band'=>'Bant','effective'=>'Geçerlilik','status'=>'Durum','actions'=>'İşlem'];private const SORTABLE=['created_at','effective_from','version','status'];public function mount():void{$this->bandEffectiveFrom=today()->toDateString();$this->salaryEffectiveFrom=today()->addMonth()->startOfMonth()->toDateString();$this->benefitStartsOn=today()->toDateString();}public function createBand(ManageSalaryBandAction $action):void{$action->execute(['code'=>$this->bandCode,'name'=>$this->bandName,'minimum'=>$this->bandMinimum,'midpoint'=>$this->bandMidpoint,'maximum'=>$this->bandMaximum,'effective_from'=>$this->bandEffectiveFrom]);$this->reset(['bandCode','bandName','bandMinimum','bandMidpoint','bandMaximum']);session()->flash('success','Ücret bandı oluşturuldu.');}public function proposeSalary(ManageSalaryRecordAction $action):void{$this->validate(['salaryEmployeeId'=>'required|integer','grossSalary'=>'required|numeric|min:0.01','salaryEffectiveFrom'=>'required|date','salaryReason'=>'required|string|max:2000']);$action->propose($this->employee($this->salaryEmployeeId),(float)$this->grossSalary,$this->salaryEffectiveFrom,$this->salaryReason,$this->salaryBandId?$this->band($this->salaryBandId):null);$this->reset(['grossSalary','salaryReason']);session()->flash('success','Ücret değişikliği onaya gönderildi.');}public function approveSalary(int $id,ManageSalaryRecordAction $action):void{$action->approve($this->record($id));session()->flash('success','Ücret değişikliği ikinci kişi tarafından onaylandı.');}public function createBenefit(ManageBenefitAction $action):void{$action->create(['code'=>$this->benefitCode,'name'=>$this->benefitName,'type'=>$this->benefitType,'employer_cost'=>$this->employerCost===''?null:$this->employerCost]);$this->reset(['benefitCode','benefitName','employerCost']);}public function assignBenefit(ManageBenefitAction $action):void{$this->validate(['benefitEmployeeId'=>'required|integer','benefitId'=>'required|integer','benefitStartsOn'=>'required|date']);$action->assign($this->employee($this->benefitEmployeeId),$this->benefit($this->benefitId),$this->benefitStartsOn,$this->employeeContribution===''?null:(float)$this->employeeContribution);$this->reset(['benefitEmployeeId','benefitId','employeeContribution']);}public function sortTable(string $field):void{abort_unless(in_array($field,self::SORTABLE,true),422);if($this->sortField===$field)$this->sortDirection=$this->sortDirection==='asc'?'desc':'asc';else{$this->sortField=$field;$this->sortDirection='asc';}}public function toggleColumn(string $key):void{abort_unless(isset(self::COLUMNS[$key]),422);if(in_array($key,['employee','actions'],true))return;$this->visibleColumns=in_array($key,$this->visibleColumns,true)?array_values(array_diff($this->visibleColumns,[$key])):array_values(array_intersect(array_keys(self::COLUMNS),[...$this->visibleColumns,$key]));}public function render(){ $tenant=app(TenantContext::class)->getId();$query=HrSalaryRecord::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->when($this->statusFilter!=='',fn($q)=>$q->where('status',$this->statusFilter))->with(['employee','band']);return view('livewire.hr.compensation.compensation-workspace',['records'=>$query->orderBy($this->sortField,$this->sortDirection)->paginate(20),'employees'=>HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->active()->orderBy('first_name')->get(),'bands'=>HrSalaryBand::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('is_active',true)->get(),'benefits'=>HrBenefit::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('is_active',true)->get(),'employeeBenefits'=>HrEmployeeBenefit::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->with(['employee','benefit'])->latest()->limit(30)->get(),'columnLabels'=>self::COLUMNS])->layout('layouts.app');}private function employee(?int $id):HrEmployee{return HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);}private function band(int $id):HrSalaryBand{return HrSalaryBand::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);}private function benefit(?int $id):HrBenefit{return HrBenefit::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);}private function record(int $id):HrSalaryRecord{return HrSalaryRecord::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);}}
